Here's some code for a Linux-based "Hello, World!" using libpng library:

```
#include <stdio.h>
#include <stdlib.h>
#include <png.h>

int main(int argc, char *argv[]) {
    FILE *fp = NULL;
    png_structp png_ptr = NULL;
    png_infop info_ptr = NULL;
    png_bytep row = NULL;

    int width = 200;
    int height = 200;
    const char *file_name = "hello.png";

    fp = fopen(file_name, "wb");
    if (!fp) {
        fprintf(stderr, "Error: Could not open file %s\n", file_name);
        return EXIT_FAILURE;
    }

    png_ptr = png_create_write_struct(PNG_LIBPNG_VER_STRING, NULL, NULL, NULL);
    if (!png_ptr) {
        fprintf(stderr, "Error: Could not create PNG write struct\n");
        return EXIT_FAILURE;
    }

    info_ptr = png_create_info_struct(png_ptr);
    if (!info_ptr) {
        fprintf(stderr, "Error: Could not create PNG info struct\n");
        png_destroy_write_struct(&png_ptr, NULL);
        return EXIT_FAILURE;
    }

    if (setjmp(png_jmpbuf(png_ptr))) {
        fprintf(stderr, "Error: PNG creation failed\n");
        png_destroy_write_struct(&png_ptr, &info_ptr);
        fclose(fp);
        return EXIT_FAILURE;
    }

    png_init_io(png_ptr, fp);
    png_set_IHDR(png_ptr, info_ptr, width, height, 8, PNG_COLOR_TYPE_RGBA,
                 PNG_INTERLACE_NONE, PNG_COMPRESSION_TYPE_DEFAULT, PNG_FILTER_TYPE_DEFAULT);
    png_write_info(png_ptr, info_ptr);
    row = (png_bytep) malloc(sizeof(png_byte) * 4 * width);
    memset(row, 127, sizeof(png_byte) * 4 * width);
    for (int i = 0; i < height; i++) {
        png_write_row(png_ptr, row);
    }
    free(row);
    png_write_end(png_ptr, NULL);
    png_destroy_write_struct(&png_ptr, &info_ptr);
    fclose(fp);
    printf("Successfully created PNG %s\n", file_name);

    return EXIT_SUCCESS;
}
```

This code creates a PNG image with a single color (all red) and saves it to the file "hello.png". The PNG is created using libpng, which is a popular open-source PNG-writing library for Linux and other platforms.

To compile and run the code, save it to a file like "hello.c", then compile it with gcc:

```
gcc -o hello hello.c -lpng
```

This will create an executable called "hello", which you can run with:

```
./hello
```

This should output "Successfully created PNG hello.png" if the PNG was created successfully. You can then view the PNG by opening it with an image viewer like Eye of GNOME or GIMP.
